#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-01

set -euo pipefail
trap 'echo "[$0] failed at line $LINENO" >&2' ERR

# =============================================================================
# Provenance-sediment check — SKILL.md body no-op audit
# =============================================================================
# SKILL.md bodies accumulate "provenance sediment": version tags like
# "(CC 2.1.9" and milestone / issue markers like "M118" or "#1466" that
# were meaningful at authoring time but are no-ops for the model reading
# the skill today. They cost prompt-cache bytes and add noise without
# changing behavior.
#
# This test scans every SKILL.md BODY (below the YAML frontmatter) for:
#   - CC version tags:   "(CC <num>"        e.g. (CC 2.1.9
#   - milestone markers: "M1[0-9][0-9]"     e.g. M118, M154
#   - issue markers:     "#[0-9]{3,4}"       e.g. #1466, #897
#
# It prints per-skill counts (top offenders) and a grand total, then
# EXITS 0. This is an INFORMATIONAL RATCHET: it establishes the current
# sediment baseline without failing the build.
#
# RATCHET INTENT: once the existing sediment is stripped from skill
# bodies, flip this to fail-on-increase (compare grand total against a
# committed baseline, fail when it grows) — mirroring the advisory→enforce
# pattern in test-directive-density.sh. Until then it exits 0 on the
# CURRENT repo state by design.
# =============================================================================

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
SKILLS_DIR="$REPO_ROOT/src/skills"

GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

# Markers considered provenance sediment (see header). Combined into one
# alternation so a single grep pass counts every occurrence in a body.
SEDIMENT_PATTERN='\(CC [0-9]|M1[0-9][0-9]|#[0-9]{3,4}'
CC_PATTERN='\(CC [0-9]'
MILESTONE_PATTERN='M1[0-9][0-9]'
ISSUE_PATTERN='#[0-9]{3,4}'

echo -e "${BLUE}${BOLD}Provenance-sediment check (SKILL.md body version/milestone/issue no-ops)${NC}"
echo -e "  Markers:  '(CC <num>'  |  'M1xx' milestones  |  '#NNN(N)' issue refs"
echo -e "  Mode:     informational ratchet (report only, always exits 0)"
echo ""

# Emit only the SKILL.md body — everything below the closing frontmatter
# delimiter. Files without frontmatter are scanned in full.
skill_body() {
    awk 'NR==1 && $0=="---" { fm=1; next }
         fm==1 && $0=="---" { fm=2; next }
         fm!=1 { print }' "$1"
}

count_pattern() {
    # $1 = extended-regex pattern; body text arrives on stdin.
    # grep's exit 1 on no-match is the expected/common case here — a body
    # with zero markers is normal — so we absorb it and count match lines.
    # silent: best-effort
    { grep -oE "$1" || true; } | wc -l | tr -d ' '
}

report_rows=()
grand_total=0
grand_cc=0
grand_milestone=0
grand_issue=0
offender_skills=0

while IFS= read -r -d '' skill_md; do
    skill_name="$(basename "$(dirname "$skill_md")")"
    body="$(skill_body "$skill_md")"

    total="$(printf '%s\n' "$body" | count_pattern "$SEDIMENT_PATTERN")"
    cc="$(printf '%s\n' "$body" | count_pattern "$CC_PATTERN")"
    milestone="$(printf '%s\n' "$body" | count_pattern "$MILESTONE_PATTERN")"
    issue="$(printf '%s\n' "$body" | count_pattern "$ISSUE_PATTERN")"

    grand_total=$((grand_total + total))
    grand_cc=$((grand_cc + cc))
    grand_milestone=$((grand_milestone + milestone))
    grand_issue=$((grand_issue + issue))

    if [[ "$total" -gt 0 ]]; then
        offender_skills=$((offender_skills + 1))
        report_rows+=("$(printf '%6d total  (CC:%-3d  M1xx:%-3d  #NNN:%-3d)  %s' \
            "$total" "$cc" "$milestone" "$issue" "$skill_name")")
    fi
done < <(find "$SKILLS_DIR" -name SKILL.md -print0 | sort -z)

# Ranked report — top 20 offenders by total sediment count
echo -e "${BOLD}Top skills by provenance sediment:${NC}"
if [[ ${#report_rows[@]} -eq 0 ]]; then
    echo -e "  ${GREEN}(none — no version/milestone/issue markers found in any body)${NC}"
else
    printf '%s\n' "${report_rows[@]}" | sort -k1 -nr | head -20 | while IFS= read -r row; do
        echo -e "  $row"
    done
fi
echo ""

echo -e "${BOLD}Grand total:${NC}"
echo -e "  Skills with sediment : ${offender_skills}"
echo -e "  CC version tags      : ${grand_cc}"
echo -e "  Milestone markers    : ${grand_milestone}"
echo -e "  Issue markers        : ${grand_issue}"
echo -e "  ${BOLD}All markers combined : ${grand_total}${NC}"
echo ""

if [[ "$grand_total" -eq 0 ]]; then
    echo -e "${GREEN}✓ No provenance sediment in any SKILL.md body.${NC}"
else
    echo -e "${YELLOW}⚠ ${grand_total} provenance no-op(s) across ${offender_skills} skill body(ies).${NC}"
    echo -e "${BLUE}  Informational only — strip these from skill bodies, then flip this${NC}"
    echo -e "${BLUE}  test to fail-on-increase against a committed baseline.${NC}"
fi

# Report-only ratchet: never fails on current repo state.
exit 0
